// Calculate daily revenue and product breakdown
const response = $input.first().json;
const sales = response.sales || [];

if (sales.length === 0) {
  return [{
    json: {
      date: new Date().toISOString().split('T')[0],
      totalRevenue: 0,
      totalSales: 0,
      topProduct: 'No sales yesterday',
      productBreakdown: [],
      avgOrderValue: 0,
      message: 'Zero sales day. Time to push content.'
    }
  }];
}

// Aggregate by product
const byProduct = {};
let totalRevenue = 0;

for (const sale of sales) {
  const productName = sale.product_name || 'Unknown Product';
  const amount = parseFloat(sale.price || 0) / 100; // Gumroad returns cents
  totalRevenue += amount;

  if (!byProduct[productName]) {
    byProduct[productName] = { name: productName, revenue: 0, count: 0 };
  }
  byProduct[productName].revenue += amount;
  byProduct[productName].count += 1;
}

const breakdown = Object.values(byProduct)
  .sort((a, b) => b.revenue - a.revenue);

const topProduct = breakdown[0];
const avgOrderValue = totalRevenue / sales.length;

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    totalRevenue: totalRevenue.toFixed(2),
    totalSales: sales.length,
    topProduct: topProduct?.name || 'N/A',
    topProductRevenue: topProduct?.revenue.toFixed(2) || '0',
    topProductCount: topProduct?.count || 0,
    productBreakdown: breakdown,
    avgOrderValue: avgOrderValue.toFixed(2),
    message: totalRevenue > 100 ? 'Solid day.' : totalRevenue > 50 ? 'Decent. Keep pushing.' : 'Light day. Need more traffic.'
  }
}];

